using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpStdioServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool("fetch_api_data"),
     Description("Fetches data from an external REST API by path (e.g. \"posts/1\", \"users\").")]
    public static async Task<string> FetchApiDataAsync(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiFetchTool> logger,
        [Description("Relative API path to fetch, e.g. \"posts/1\".")] string path,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching external API path: {Path}", path);

        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpStdioServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt("summarize"),
     Description("Generates a prompt that asks the LLM to summarize the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Optional desired length: \"short\", \"medium\", or \"long\".")] string? length = "medium")
    {
        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Type = "text",
                    Text = $"""
                        Please provide a {length} summary of the following text.
                        Focus on the key points and main ideas.

                        ---
                        {text}
                        ---
                        """
                }
            }
        ];
    }
}

